content.text:
An elegant, real-time cooperative Kanban board has been designed and implemented in a single self-contained application using Google's **Polaris / Material Design 3 (M3)** specifications and integrated with the Workspace sync service.

### State Update
* Thinking about data structure
* Building visual component architecture
* Writing client synchronization code

Here is the complete, self-contained application `index.html`:

```html
<!-- index.html -->
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Project Ollie Task Tracker</title>

  <!-- Tailwind CSS CDN -->
  <script src="https://cdn.tailwindcss.com"></script>

  <!-- Google Fonts -->
  <link href="https://fonts.googleapis.com/css2?family=Google+Sans:wght@400;500;700&family=Google+Sans+Text:wght@400;500&display=swap" rel="stylesheet">

  <style>
    :root {
      --gemini-rail-icon-gap: 0px;
      --gemini-side-panel-padding-left: 16px;
      --gemini-side-panel-padding-right: 16px;
      --gemini-header-padding-left: 10px;
      --gemini-header-padding-right: 12px;
      --gemini-header-elements-gap: 8px;

      /* Material Design 3 (M3) Tokens */
      --primary: #0b57d0;
      --on-primary: #ffffff;
      --primary-container: #d3e3fd;
      --surface: #ffffff;
      --surface-container: #f0f4f9;
      --outline: #747775;
      --text-main: #131314;
    }

    body {
      font-family: 'Google Sans Text', sans-serif;
      background-color: var(--surface);
      color: var(--text-main);
      margin: 0;
      padding: 0;
    }

    h1, h2, h3 {
      font-family: 'Google Sans', sans-serif;
    }

    .column-height {
      min-height: calc(100vh - 240px);
    }

    .drag-over {
      background-color: #e3ebf7 !important;
      border: 2px dashed var(--primary);
    }
  </style>
</head>
<body class="p-6 bg-[#ffffff]">

  <!-- Main Container -->
  <div class="max-w-7xl mx-auto">

    <!-- Top Workspace Header -->
    <header class="flex flex-col md:flex-row md:items-center md:justify-between pb-6 border-b border-gray-200 mb-6">
      <div>
        <div class="flex items-center gap-2">
          <span class="inline-block w-3 h-3 rounded-full bg-[#0b57d0] animate-pulse"></span>
          <h1 class="text-2xl font-medium tracking-tight text-[#131314]">Project Ollie Task Board</h1>
        </div>
        <p class="text-sm text-gray-500 mt-1">
          Workspace: <span id="workspace-name" class="font-medium text-gray-700">Loading Workspace...</span>
        </p>
      </div>

      <!-- Sync Status -->
      <div class="flex items-center gap-2 mt-3 md:mt-0 bg-[#f0f4f9] px-3 py-1.5 rounded-full text-xs text-gray-600 border border-gray-200">
        <svg class="w-4 h-4 text-[#0b57d0] animate-spin" id="sync-spinner" fill="none" viewBox="0 0 24 24">
          <circle class="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" stroke-width="4"></circle>
          <path class="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
        </svg>
        <span id="sync-status">Syncing real-time changes</span>
      </div>
    </header>

    <!-- Radical Simplicity Add Task Bar -->
    <section class="bg-[#f0f4f9] p-4 rounded-xl border border-gray-200 mb-8">
      <h2 class="text-sm font-medium text-[#131314] mb-3">Add New Team Task</h2>
      <form id="add-task-form" class="flex flex-col sm:flex-row gap-3">
        <input 
          type="text" 
          id="task-title" 
          required
          placeholder="What needs to be done? (e.g. Implement Spanner cycle-detection)" 
          class="flex-1 bg-white px-4 py-2 text-sm rounded-lg border border-gray-300 focus:outline-none focus:ring-2 focus:ring-[#0b57d0] text-gray-800"
        />

        <select 
          id="task-assignee" 
          class="bg-white px-3 py-2 text-sm rounded-lg border border-gray-300 focus:outline-none focus:ring-2 focus:ring-[#0b57d0] text-gray-700"
        >
          <!-- Filled dynamically via JS -->
        </select>

        <button 
          type="submit" 
          class="bg-[#0b57d0] hover:bg-[#0842a0] text-white px-5 py-2 text-sm font-medium rounded-lg transition-colors focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-[#0b57d0]"
        >
          Add Task
        </button>
      </form>
    </section>

    <!-- 3-Column Simple Kanban Grid -->
    <main class="grid grid-cols-1 md:grid-cols-3 gap-6">

      <!-- TO DO COLUMN -->
      <div class="bg-[#f0f4f9] rounded-xl border border-gray-200 flex flex-col p-4">
        <div class="flex justify-between items-center pb-3 border-b border-gray-200 mb-4">
          <h3 class="font-medium text-[#131314] flex items-center gap-2">
            To Do
            <span id="count-todo" class="bg-gray-200 text-gray-700 text-xs px-2.5 py-0.5 rounded-full font-bold">0</span>
          </h3>
        </div>
        <div id="col-todo" class="column-height flex flex-col gap-3" ondragover="allowDrop(event)" ondrop="drop(event, 'todo')" ondragleave="dragLeave(event)">
          <!-- Cards go here -->
        </div>
      </div>

      <!-- IN PROGRESS COLUMN -->
      <div class="bg-[#f0f4f9] rounded-xl border border-gray-200 flex flex-col p-4">
        <div class="flex justify-between items-center pb-3 border-b border-gray-200 mb-4">
          <h3 class="font-medium text-[#131314] flex items-center gap-2">
            In Progress
            <span id="count-inprogress" class="bg-[#d3e3fd] text-[#0b57d0] text-xs px-2.5 py-0.5 rounded-full font-bold">0</span>
          </h3>
        </div>
        <div id="col-inprogress" class="column-height flex flex-col gap-3" ondragover="allowDrop(event)" ondrop="drop(event, 'inprogress')" ondragleave="dragLeave(event)">
          <!-- Cards go here -->
        </div>
      </div>

      <!-- DONE COLUMN -->
      <div class="bg-[#f0f4f9] rounded-xl border border-gray-200 flex flex-col p-4">
        <div class="flex justify-between items-center pb-3 border-b border-gray-200 mb-4">
          <h3 class="font-medium text-[#131314] flex items-center gap-2">
            Done
            <span id="count-done" class="bg-green-100 text-green-700 text-xs px-2.5 py-0.5 rounded-full font-bold">0</span>
          </h3>
        </div>
        <div id="col-done" class="column-height flex flex-col gap-3" ondragover="allowDrop(event)" ondrop="drop(event, 'done')" ondragleave="dragLeave(event)">
          <!-- Cards go here -->
        </div>
      </div>

    </main>
  </div>

  <!-- JavaScript and Workspace Sync Integrations -->
  <script>
    // Real Team Members Context Database
    const teamMembers = [
      { name: "Stephanie Goodson", email: "sgoodson@google.com", avatar: "https://lh3.googleusercontent.com/a-/ALV-UjXhSTeKdBDfDYWa6uS5J89rBh2uJHVV8OHoEUKYEe8AVFjY-4Q=s64" },
      { name: "Chris Carroll", email: "cdcarroll@google.com", avatar: "https://lh3.googleusercontent.com/a-/ALV-UjVbB5SNQqui8-Dhh4ttI-p8lTdndJGcwTKlRrPnnNuKpJEXlKqF=s64" },
      { name: "Jannica Robertson", email: "jannicar@google.com", avatar: "https://lh3.googleusercontent.com/a-/ALV-UjWDycqL54QiGjUCQolQXjRQ80GsUFizqLOjmWN5j5IAy9-NLFIO=s64" },
      { name: "Frank Tisellano", email: "ftj@google.com", avatar: "https://lh3.googleusercontent.com/a-/ALV-UjWIXtfhCFx8S8zhFpLAaF9NZSiDJZmtDjpzW8DRqDnltb-otP9-=s64" },
      { name: "Megan Bruce", email: "meganbruce@google.com", avatar: "https://lh3.googleusercontent.com/a-/ALV-UjW14QaUGF52yVyOkgsoQgDd7YxKtA3flS0Y-FgQSpfMlPB5Cib_=s64" },
      { name: "Ajay Yadav", email: "yadavajay@google.com", avatar: "https://lh3.googleusercontent.com/a-/ALV-UjW5ytDzOzOxOMnVKGMTlZFIQFZGQE-F3hF9WT2C3_8rKFkSa6V4xQ=s64" },
      { name: "Belinda Preno", email: "belindapreno@google.com", avatar: "https://lh3.googleusercontent.com/a-/ALV-UjW8kkayF4FN3ib50ZpJsNFIMcSF9CLOgEcXNjlG9yhQ2xy1dL2q=s64" },
      { name: "Emily Thomas", email: "emilyjthomas@google.com", avatar: "https://lh3.googleusercontent.com/a-/ALV-UjVsXrPitMvyKTee1jfDjpODeKXAkN05NFP-MujtVh_GF6LFi1qw=s64" },
      { name: "Daniel Giuditta", email: "danielgiuditta@google.com", avatar: "https://lh3.googleusercontent.com/a/ACg8ocI4XtQJyOGEbExqDChL5Jutn2AfMdv-Yaq9Pbdd1NMuBb-qO08=s64" },
      { name: "Zhengrong Ji", email: "jizr@google.com", avatar: "https://lh3.googleusercontent.com/a-/ALV-UjWcXn2VmhyBKHwqviKOHkMtMPnIR1VFjOlNEyIMFrFI2C0Pt0Zj=s64" },
      { name: "Ryan Spohn", email: "rspohn@google.com", avatar: "https://lh3.googleusercontent.com/a-/ALV-UjVbqXCvGLcBpDuCdv05JUnymeuoDYoUYTELHxdY4k_5BhnH6GWHMg=s64" },
      { name: "Laurence Fahey", email: "laurencefahey@google.com", avatar: "https://lh3.googleusercontent.com/a/ACg8ocLLL2cXiri5iV3mBRXg2mYrij2OJg28l3nTJrtWU5YQlotT2iUH=s64" },
      { name: "Ian Mendiola", email: "ianmendiola@google.com", avatar: "https://lh3.googleusercontent.com/a-/ALV-UjUP0nZZSsC7tRQg_3si0rRn-TJyMoD8j0kfQm3I-HdLEIVQYBsG=s64" },
      { name: "David Wurtz", email: "wurtz@google.com", avatar: "https://lh3.googleusercontent.com/a-/ALV-UjW7KVh0yVuDb5C5TdRwGD7YYrY9iwTZzjNklnwKjpKGKeTFhayw=s64" }
    ];

    // Initial default state tasks if synchronized space is empty
    const defaultTasks = [
      { id: "task-1", title: "Implement Spanner cycle-detection CTE in CreateSubTask", status: "todo", assigneeEmail: "ianmendiola@google.com" },
      { id: "task-2", title: "Design hybrid semantic + BM25 retrieval for Memory Service", status: "todo", assigneeEmail: "jizr@google.com" },
      { id: "task-3", title: "Sobi Harness: Add agent_extension.go permission checking", status: "inprogress", assigneeEmail: "cdcarroll@google.com" },
      { id: "task-4", title: "Create UX Research Interview plan for baseline workflows", status: "inprogress", assigneeEmail: "sgoodson@google.com" },
      { id: "task-5", title: "DDL: Setup FactualFacts & MemoryACLs Spanner tables", status: "done", assigneeEmail: "rspohn@google.com" },
      { id: "task-6", title: "Draft High Level Design (HLD) document for Project Ollie", status: "done", assigneeEmail: "ftj@google.com" }
    ];

    let state = {
      tasks: []
    };

    let localStateString = "";
    const envId = window.__sandboxEnvId;
    const syncKey = "project_ollie_board_state";

    // Setup initial workspace title
    document.getElementById("workspace-name").innerText = window.__sandboxWorkspaceName || "Default Workspace";

    // Build Assignee Dropdown Options
    const assigneeSelect = document.getElementById("task-assignee");
    teamMembers.forEach(member => {
      const option = document.createElement("option");
      option.value = member.email;
      option.textContent = member.name;
      assigneeSelect.appendChild(option);
    });

    // Load Synced State
    async function loadSyncedState() {
      if (!envId) {
        // Fallback to local storage if not running inside the platform sandbox
        const localData = localStorage.getItem(syncKey);
        if (localData) {
          updateUI(JSON.parse(localData));
        } else {
          updateUI({ tasks: defaultTasks });
        }
        showSyncCompleted();
        return;
      }

      try {
        const res = await fetch(`/api/sync/${envId}/${syncKey}`);
        const json = await res.json();
        if (json.data && json.data.tasks) {
          updateUI(json.data);
        } else {
          // Initialize with default tasks if empty
          await saveSyncedState({ tasks: defaultTasks });
          updateUI({ tasks: defaultTasks });
        }
        showSyncCompleted();
      } catch (err) {
        console.error("Failed to load synced state:", err);
        showSyncError();
      }
    }

    // Save Synced State
    async function saveSyncedState(newState) {
      if (!envId) {
        localStorage.setItem(syncKey, JSON.stringify(newState));
        updateUI(newState);
        return;
      }

      showSyncing();
      try {
        await fetch(`/api/sync/${envId}/${syncKey}`, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ data: newState })
        });
        updateUI(newState);
        showSyncCompleted();
      } catch (err) {
        console.error("Failed to save synced state:", err);
        showSyncError();
      }
    }

    function updateUI(newState) {
      const newStateString = JSON.stringify(newState);
      if (newStateString === localStateString) return; // Prevent unnecessary redraws
      localStateString = newStateString;
      state = newState;
      renderBoard();
    }

    function renderBoard() {
      const columns = {
        todo: document.getElementById("col-todo"),
        inprogress: document.getElementById("col-inprogress"),
        done: document.getElementById("col-done")
      };

      // Clear all columns
      Object.values(columns).forEach(col => col.innerHTML = "");

      // Counter monitors
      const counts = { todo: 0, inprogress: 0, done: 0 };

      state.tasks.forEach(task => {
        counts[task.status]++;
        const assignee = teamMembers.find(m => m.email === task.assigneeEmail) || { name: "Unassigned", avatar: "" };

        // Build beautiful minimalist card
        const card = document.createElement("div");
        card.id = task.id;
        card.draggable = true;
        card.className = "bg-white p-4 rounded-xl border border-gray-200 shadow-sm hover:border-gray-400 transition-all cursor-grab active:cursor-grabbing relative group";
        card.setAttribute("ondragstart", `drag(event, '${task.id}')`);

        // Avatar template rule check
        const avatarImg = assignee.avatar 
          ? `<img src="${assignee.avatar}" alt="${assignee.name}" class="w-5 h-5 rounded-full object-cover">`
          : `<div class="w-5 h-5 rounded-full bg-blue-100 flex items-center justify-center text-[10px] font-bold text-blue-600">${assignee.name.split(" ").map(n => n[0]).join("")}</div>`;

        // Left/Right control buttons for fluid interactive modifications
        let navButtons = ``;
        if (task.status === "todo") {
          navButtons = `<button onclick="moveStatus('${task.id}', 'inprogress')" class="p-1 rounded hover:bg-gray-100 text-gray-500 hover:text-blue-600" title="Move to In Progress">>→</button>`;
        } else if (task.status === "inprogress") {
          navButtons = `
            <button onclick="moveStatus('${task.id}', 'todo')" class="p-1 rounded hover:bg-gray-100 text-gray-500 hover:text-blue-600" title="Move to To Do">←</button>
            <button onclick="moveStatus('${task.id}', 'done')" class="p-1 rounded hover:bg-gray-100 text-gray-500 hover:text-blue-600" title="Move to Done">>→</button>
          `;
        } else if (task.status === "done") {
          navButtons = `<button onclick="moveStatus('${task.id}', 'inprogress')" class="p-1 rounded hover:bg-gray-100 text-gray-500 hover:text-blue-600" title="Move to In Progress">←</button>`;
        }

        card.innerHTML = `
          <div class="flex flex-col gap-3">
            <p class="text-sm font-normal text-gray-800 leading-snug pr-6">${escapeHtml(task.title)}</p>

            <div class="flex items-center justify-between border-t border-gray-100 pt-3">
              <div class="flex items-center gap-1.5">
                ${avatarImg}
                <span class="text-xs text-gray-500 font-medium">${assignee.name}</span>
              </div>

              <div class="flex items-center gap-1">
                ${navButtons}
                <button onclick="deleteTask('${task.id}')" class="p-1 rounded hover:bg-red-50 text-gray-400 hover:text-red-500 transition-colors" title="Delete task">
                  <svg class="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-16v1a1 1 0 001 1h3m-6 0a1 1 0 001-1V4a1 1 0 00-1-1h-3a1 1 0 00-1 1v1m-6 0h18"></path>
                  </svg>
                </button>
              </div>
            </div>
          </div>
        `;

        if (columns[task.status]) {
          columns[task.status].appendChild(card);
        }
      });

      // Update indicators
      document.getElementById("count-todo").textContent = counts.todo;
      document.getElementById("count-inprogress").textContent = counts.inprogress;
      document.getElementById("count-done").textContent = counts.done;
    }

    // HTML sanitizer to prevent XSS injection
    function escapeHtml(text) {
      const div = document.createElement('div');
      div.innerText = text;
      return div.innerHTML;
    }

    // Interactive action triggers
    async function moveStatus(taskId, newStatus) {
      const updatedTasks = state.tasks.map(task => {
        if (task.id === taskId) {
          return { ...task, status: newStatus };
        }
        return task;
      });
      await saveSyncedState({ tasks: updatedTasks });
    }

    async function deleteTask(taskId) {
      const updatedTasks = state.tasks.filter(task => task.id !== taskId);
      await saveSyncedState({ tasks: updatedTasks });
    }

    // Add New Task Submissions
    document.getElementById("add-task-form").addEventListener("submit", async (e) => {
      e.preventDefault();
      const titleInput = document.getElementById("task-title");
      const assigneeSelect = document.getElementById("task-assignee");

      const newTask = {
        id: "task-" + Date.now(),
        title: titleInput.value.trim(),
        status: "todo",
        assigneeEmail: assigneeSelect.value
      };

      const updatedTasks = [...state.tasks, newTask];
      await saveSyncedState({ tasks: updatedTasks });

      titleInput.value = "";
    });

    // HTML5 Drag and Drop Handlers
    function drag(ev, taskId) {
      ev.dataTransfer.setData("text/plain", taskId);
      ev.currentTarget.classList.add("opacity-50");
    }

    function allowDrop(ev) {
      ev.preventDefault();
      const column = ev.currentTarget;
      if (!column.classList.contains("drag-over")) {
        column.classList.add("drag-over");
      }
    }

    function dragLeave(ev) {
      ev.currentTarget.classList.remove("drag-over");
    }

    async function drop(ev, status) {
      ev.preventDefault();
      const column = ev.currentTarget;
      column.classList.remove("drag-over");

      const taskId = ev.dataTransfer.getData("text/plain");
      const card = document.getElementById(taskId);
      if (card) {
        card.classList.remove("opacity-50");
      }

      await moveStatus(taskId, status);
    }

    // Sync state feedback helper routines
    function showSyncing() {
      document.getElementById("sync-spinner").classList.remove("hidden");
      document.getElementById("sync-status").textContent = "Saving modifications...";
    }

    function showSyncCompleted() {
      document.getElementById("sync-spinner").classList.add("hidden");
      document.getElementById("sync-status").textContent = "All changes synchronized";
    }

    function showSyncError() {
      document.getElementById("sync-spinner").classList.add("hidden");
      document.getElementById("sync-status").textContent = "Offline Mode / Connection Lost";
    }

    // Short-poll state every 2 seconds to retrieve multiplayer changes live
    loadSyncedState();
    if (envId) {
      setInterval(loadSyncedState, 2000);
    }
  </script>
</body>
</html>
```
